import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './App.css';

function App() {
  const [schemes, setSchemes] = useState([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [filteredSchemes, setFilteredSchemes] = useState([]);

  useEffect(() => {
    fetchSchemes();
  }, []);

  const fetchSchemes = async () => {
    try {
      const response = await axios.get('/api/schemes');
      setSchemes(response.data);
      setFilteredSchemes(response.data);
    } catch (error) {
      console.error('Error fetching schemes:', error);
    }
  };

  const handleSearch = async () => {
    try {
      const response = await axios.get(`/api/schemes/search?query=${searchQuery}`);
      setFilteredSchemes(response.data);
    } catch (error) {
      console.error('Error searching schemes:', error);
    }
  };

  return (
    <div className="App">
      <header className="App-header">
        <h1>YojanaAI — Government Scheme Finder</h1>
        <p>Find every government scheme you deserve — in your language, instantly, with AI fraud protection.</p>
      </header>
      <main>
        <div className="search-bar">
          <input
            type="text"
            placeholder="Search for schemes..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
          <button onClick={handleSearch}>Search</button>
        </div>
        <div className="schemes-grid">
          {filteredSchemes.map((scheme) => (
            <div key={scheme._id} className="scheme-card">
              <h3>{scheme.scheme_name}</h3>
              <p><strong>Category:</strong> {scheme.category}</p>
              <p><strong>State:</strong> {scheme.state}</p>
              <p><strong>Eligibility:</strong> {scheme.eligibility_criteria}</p>
              <p><strong>Benefits:</strong> {scheme.benefits}</p>
              <p><strong>Summary:</strong> {scheme.summary}</p>
              <a href={scheme.application_link} target="_blank" rel="noopener noreferrer">Apply Here</a>
            </div>
          ))}
        </div>
      </main>
    </div>
  );
}

export default App;
